var body = $input.first().json.body || $input.first().json;
var tenantId = String(body.tenantId || '');
var exerciceId = String(body.exerciceId || '');
var annee = body.annee ? parseInt(body.annee) : null;

var UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!tenantId || !UUID_RE.test(tenantId)) {
  throw new Error('Tenant ID requis et doit être un UUID valide');
}
if (!exerciceId || !UUID_RE.test(exerciceId)) {
  throw new Error('Exercice ID requis et doit être un UUID valide');
}

return [{
  json: {
    tenantId: tenantId,
    exerciceId: exerciceId,
    annee: annee
  }
}];

var exerciceData = $('05. Get Exercice').first().json;
var existingCount = $('06. Check Existing').first().json.nb_existing || 0;

if (!exerciceData || !exerciceData.date_debut || !exerciceData.date_fin) {
  throw new Error('Exercice non trouvé ou dates invalides');
}

if (existingCount > 0) {
  throw new Error('Les périodes pour cet exercice existent déjà');
}

var startDate = new Date(exerciceData.date_debut);
var endDate = new Date(exerciceData.date_fin);
var currentDate = new Date(startDate);
var periodes = [];

var months = ['Janvier', 'Février', 'Mars', 'Avril', 'Mai', 'Juin', 'Juillet', 'Août', 'Septembre', 'Octobre', 'Novembre', 'Décembre'];

for (var i = 0; i < 12; i++) {
  var monthStart = new Date(currentDate);
  var monthEnd = new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 0);

  // Cap end date to exercice end date
  if (monthEnd > endDate) {
    monthEnd = new Date(endDate);
  }

  var code = monthStart.getFullYear() + '-' + String(monthStart.getMonth() + 1).padStart(2, '0');
  var libelle = months[monthStart.getMonth()] + ' ' + monthStart.getFullYear();

  periodes.push({
    code: code,
    libelle: libelle,
    dateDebut: monthStart.toISOString().split('T')[0],
    dateFin: monthEnd.toISOString().split('T')[0],
    statut: 'ouverte'
  });

  currentDate.setMonth(currentDate.getMonth() + 1);
}

return [{json: {periodes: periodes}}];

var periodes = $('07. Generate Periodes').first().json.periodes;
var tenantId = $('02. Parser').first().json.tenantId;
var exerciceId = $('02. Parser').first().json.exerciceId;

var values = periodes.map(function(p) {
  var code = p.code.replace(/'/g, "''");
  var libelle = p.libelle.replace(/'/g, "''");
  return "(gen_random_uuid(), '" + tenantId + "', '" + exerciceId + "', '" + code + "', '" + libelle + "', '" + p.dateDebut + "', '" + p.dateFin + "', '" + p.statut + "', NOW(), NOW())";
}).join(',\n');

var query = "INSERT INTO periodes_comptables (id, tenant_id, exercice_id, code, libelle, date_debut, date_fin, statut, created_at, updated_at) VALUES " + values + " RETURNING *";

return [{json: {query: query}}];

var items = $input.all();
var periodes = items.map(function(item) { return item.json; }).filter(function(r) { return r && r.id; });

if (periodes.length === 0) {
  return [{json: {success: false, error: 'Création des périodes échouée'}}];
}

var formattedPeriodes = periodes.map(function(p) {
  return {
    id: p.id,
    code: p.code,
    libelle: p.libelle,
    dateDebut: p.date_debut,
    dateFin: p.date_fin,
    statut: p.statut,
    createdAt: p.created_at
  };
});

return [{json: {success: true, count: formattedPeriodes.length, periodes: formattedPeriodes}}];
